// Нормализуем вход. Главный роутер (Code in JavaScript1) кладёт исходное тело в raw_payload,
// а company_id/token/user_id поднимает на верхний уровень. Поддерживаем и прямой вызов.
const input = items[0]?.json ?? {};
const isObj = (v) => v && typeof v === 'object' && !Array.isArray(v);
const rp = isObj(input.raw_payload) ? input.raw_payload : input;
const src = isObj(rp.payload) ? rp.payload : rp;
const pick = (k) => input[k] ?? src[k] ?? rp[k] ?? null;

const session = {
  company_id: pick('company_id'),
  token: pick('token'),
  user_id: pick('user_id'),
};

const action_key = String(src.action_key ?? '').trim();
const workflow_id = src.workflow_id ? String(src.workflow_id).trim() : '';
const department = src.department ? String(src.department).trim() : '';
const operation = String(src.operation ?? '').trim();
const params = isObj(src.params) ? src.params : {};
const confirmed = src.confirmed === true || src.confirmed === 'true';
const idempotency_key = src.idempotency_key ?? (require('crypto').randomUUID());
const requires_approval = src.requires_human_approval === true || src.requires_human_approval === 'true';

let _gate = 'run';
if (!action_key && !workflow_id) _gate = 'error';
else if (requires_approval && !confirmed) _gate = 'approval';
else if (!workflow_id) _gate = 'error';

return [{ json: { _gate, action_key, workflow_id, department, operation, params, confirmed, idempotency_key, ...session } }];

// Оборачиваем параметры режима в конверт, который ждут хендлеры.
// issue_invoice читает action.params.payload; yookassa — payload.operation + payload поля; ops_finance — payload.user_message.
const j = items[0]?.json ?? {};
const params = (j.params && typeof j.params === 'object') ? j.params : {};
const operation = j.operation || params.operation || '';
const payload = { ...params };
if (operation) payload.operation = operation;
const company_id = j.company_id || null;
const user_id = j.user_id || null;
const token = j.token || null;
const envelope = {
  // важно сохранить для ноды запуска (берёт workflow_id из выражения)
  workflow_id: j.workflow_id,
  company_id, user_id, token,
  action_key: j.action_key,
  operation,
  action: { action_key: j.action_key, company_id, params: { operation, payload } },
  params: { operation, payload },
  payload,
  paymentRequest: payload,
  idempotency_key: j.idempotency_key,
};
return [{ json: envelope }];

// Приводим результат обработчика к контракту клиента.
const out = items[0]?.json ?? {};
if (out.error) {
  return [{ json: { ok: false, status: 'error', error: String(out.error?.message ?? out.error) } }];
}
const result = out.data ?? out.result ?? out;
const lo = result?.llm_output ?? out.llm_output ?? {};
const text = out.text ?? out.message ?? result?.text ?? result?.message
  ?? lo.final_response ?? result?.final_response ?? result?.summary
  ?? out.final_response ?? 'Действие выполнено';
return [{ json: { ok: true, status: 'done', result, text: String(text) } }];
